module binary_counter(reset_clk, enable, count);

    input  reset_clk;  
    input  enable;  
    output [2:0] count;  
    reg    [2:0] count; 
    initial count = 0;

    always @(posedge reset_clk)
        begin
            if (enable)
                count <= count + 1;
            else
                count <= count;
        end  

endmodule
